   401	Expr*
   402	Ast2Asg::operator()(ast::UnaryExpressionContext* ctx)
   403	{
   404	  if (auto p = ctx->postfixExpression())
   405	    return self(p);
   406	
   407	  auto ret = make<UnaryExpr>();
   408	
   409	  switch (
   410	    dynamic_cast<antlr4::tree::TerminalNode*>(ctx->unaryOperator()->children[0])
   411	      ->getSymbol()
   412	      ->getType()) {
   413	    case ast::Plus:
   414	      ret->op = ret->kPos;
   415	      break;
   416	
   417	    case ast::Minus:
   418	      ret->op = ret->kNeg;
   419	      break;
   420	
   421	    default:
   422	      ABORT();
   423	  }
   424	
   425	  ret->sub = self(ctx->unaryExpression());
   426	
   427	  return ret;
   428	}
