   438	Expr*
   439	Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
   440	{
   441	
   442	  if (auto p = ctx->Identifier()) {
   443	    auto name = p->getText();
   444	    auto ret = make<DeclRefExpr>();
   445	    ret->decl = mSymtbl->resolve(name);
   446	    return ret;
   447	  }
   448	
   449	  if (auto p = ctx->Constant()) {
   450	    auto text = p->getText();
   451	
   452	    auto ret = make<IntegerLiteral>();
   453	
   454	    ASSERT(!text.empty());
   455	    if (text[0] != '0')
   456	      ret->val = std::stoll(text);
   457	
   458	    else if (text.size() == 1)
   459	      ret->val = 0;
   460	
   461	    else if (text[1] == 'x' || text[1] == 'X')
   462	      ret->val = std::stoll(text.substr(2), nullptr, 16);
   463	
   464	    else
   465	      ret->val = std::stoll(text.substr(1), nullptr, 8);
   466	
   467	    return ret;
   468	  }
   469	
   470	  ABORT();
   471	}
