   473	Expr*
   474	Ast2Asg::operator()(ast::InitializerContext* ctx)
   475	{
   476	  if (auto p = ctx->assignmentExpression())
   477	    return self(p);
   478	
   479	  auto ret = make<InitListExpr>();
   480	
   481	  if (auto p = ctx->initializerList()) {
   482	    for (auto&& i : p->initializer()) {
   483	      // 将初始化列表展平
   484	      auto expr = self(i);
   485	      if (auto p = expr->dcst<InitListExpr>()) {
   486	        for (auto&& sub : p->list)
   487	          ret->list.push_back(sub);
   488	      } else {
   489	        ret->list.push_back(expr);
   490	      }
   491	    }
   492	  }
   493	
   494	  return ret;
   495	}
